#include <bits/stdc++.h>
using namespace std;

const int N = 2e4 + 5;
int fa[2 * N];

struct Str
{
    int a, b, c;
    void read()
    {
        cin >> a >> b >> c;
    }
}a[100005];

bool cmp(Str x, Str y)
{
    return x.c > y.c;
}

int find(int x)
{
    return fa[x] == x ? x : fa[x] = find(fa[x]);
}

void merge(int x, int y)
{
    fa[find(x)] = find(y);
}

int main()
{
    int n, m;
    cin >> n >> m;
    for(int i = 1; i <= 2 * n + 1; i++)
        fa[i] = i;
    for(int i = 1; i <= m; i++)
        a[i].read();
    sort(a + 1, a + m + 1, cmp);
    for(int i = 1; i <= m; i++)
    {
        int x = a[i].a, y = a[i].b, t = a[i].c;
        if(find(x) == find(y))
        {
            cout << t;
            return 0;
        }
        merge(x, y + n);
        merge(y, x + n);
    }
    cout << 0;
    return 0;
}
